var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"음……. 나이엘은 역시 오늘도 안 왔네.","JPN":"うーん……やっぱりナイエルは今日も来てないね。","ENG":"Mm... Naielle didn't come to class again today.","TWN":"嗯……奈爾今天也沒來呢。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"그런 일을 겪었으니, 아직 안정이 필요할 것일지도 모르겠구려.","JPN":"あんな経験をしたのだから、まだ安静が必要かもしれませんね。","ENG":"After all that she went through, perhaps she needs some rest.","TWN":"經歷了那種事，現在可能還需要休養。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_DESPAIR"}}}},{"id":"L6_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"시뮬레이션이라고 해도, 정신적 소모가 클 테니 말이오.","JPN":"シミュレーションだったとはいえ、精神的に消耗が激しかったはずです。","ENG":"Even if it was a simulation, the mental drain would be burdensome.","TWN":"即使是模擬，精神消耗也會很大。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"오랜만에 아카데미의 빅 뉴스를 전달해 주려 했는데…….","JPN":"久しぶりにアカデミーのビッグニュースを伝えたかったのに……","ENG":"But I came to tell her some big news about the Academy...","TWN":"，本來想跟她說學院的大新聞的……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L8_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"……쓸쓸하오?","JPN":"……寂しいんですか？","ENG":"...Do you feel lonely?","TWN":"……覺得孤單嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그럴 리가! 모처럼 교실도 조용해졌고, 좋지 뭘!","JPN":"ま、まさか！　教室も静かになったし、いいことじゃない！","ENG":"N-no way! The classroom is super quiet, and I love it!","TWN":"怎，怎麼可能！好不容易教室安靜下來了，這不是很好嗎！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L10_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"너무 걱정 마시오. 나이엘 이라면 금방 회복하고 복귀할 것이오.","JPN":"心配ご無用です。ナイエルならすぐ回復して復帰するでしょう。","ENG":"Do not worry. Naielle will recover and return soon.","TWN":"不要太擔心。如果是奈爾的話，很快就會恢復並歸隊的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"}}}},{"id":"L12_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"……수업 끝나면 함께 병문안이라도 가보는 건 어떻소?","JPN":"……授業が終わったら、共にお見舞いに行くのはどうでしょうか？","ENG":"...I suggest we go visit her at the hospital after school.","TWN":"……下課之後一起去探病怎麼樣？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"내색하진 않겠지만, 분명 기뻐할 거라 생각하오.","JPN":"顔には出さずとも、きっと喜ぶと思います。","ENG":"She might not show it, but I am certain it will brighten her day.","TWN":"雖然不會表現出來，但她一定會很高興的。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그럴까……?","JPN":"そ、そうかな……？","ENG":"D-do you really think so...?","TWN":"是，是這樣嗎……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"잠깐! 그렇게 말하니까 마치 내가 너무 간절하다는 것 같은데……?","JPN":"って、まるであたしがすごく気にしてるみたいに聞こえるんだけど！","ENG":"Wait! If you say it like that, it makes me look desperate...!","TWN":"等一下！你這麼說，好像我很想似的……？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L20_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"으앗, 깜짝이야?! 언제부터 여기 있었어?","JPN":"わあっ、びっくりした！　いつからいたの？","ENG":"Huh? WHOA! Since when were you there?","TWN":"哇，嚇我一跳？！你什麼時候在這裡的？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"빅 뉴스 할 때부터 있었다 왜!","JPN":"ビッグニュースのところからいたけど！","ENG":"From when you said something about big news!","TWN":"從你說大新聞開始就在了！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L24_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"그, 그럼 처음부터 있었잖아?","JPN":"じゃ、じゃあ最初からいたんじゃない？","ENG":"Th-then you heard everything?","TWN":"那，那從一開始就在了啊？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"흥, 내가 아직 안정이 필요하다고? 난 그때부터 계속 쌩쌩했거든?","JPN":"ふん！　まだ安静が必要？　私はあの時からずーっとぴんぴんしてるけど？","ENG":"Hmph. You still think I need to rest? I regained my strength a long time ago.","TWN":"哼，我還需要休息？我從那時候起就一直精神抖擻得咧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_PRIDE"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"거기서 쓰러져버리면 최강의 엘리트의 칭호가 달아난다구~","JPN":"あんなとこで倒れたら、最強エリートの名が泣くじゃない。","ENG":"You see, if I had fallen there, I would've lost my title as the best elite!","TWN":"如果在那倒下的話，最強精英的稱號就會溜走喔～"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CIEL_ACADEMY_NULL_NULL","text":{"KOREA":"후후, 무사히 돌아와 줘서 안심이오.","JPN":"ふふ、無事帰ってきてくれて安心しました。","ENG":"Haha. I am relieved that you returned safely.","TWN":"呵呵，平安歸來就好。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"CIEL_ACADEMY_NULL_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"그래서, 빅 뉴스란 게 뭔데?","JPN":"で、何？　そのビッグニュースってのは。","ENG":"So, what's the big news?","TWN":"所以，大新聞是什麼？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":null,"R":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"}}}},{"id":"L33_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"또 말하다 말고 도망치기만 해봐?","JPN":"また途中で逃げたら容赦しないからね。","ENG":"And don't you dare run away mid-sentence again!","TWN":"你敢再說一半試試？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_SURPRISE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}},"sfx":"FX_CUTSCEN_BOW"},{"id":"L34_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 알았어! 왜 붙잡는 거야?!","JPN":"わ、わかったよ！　わかったから放して！","ENG":"I-I won't! Will you let me go?!","TWN":"知，知道啦！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_HATE"},"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"이번에 또 새로운 선생님이 아카데미에 찾아오신대.","JPN":"今回、また新しい先生がアカデミーに来るんだって。","ENG":"A new teacher is coming to the Academy.","TWN":"這次又有新的老師來學院了。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"너도 들으면 깜짝 놀랄걸? 누구일 것 같아?","JPN":"誰だと思う？　聞いたらナイエルもびっくりするよ。","ENG":"I'm sure you'll be surprised to hear who it is. Have any guesses?","TWN":"你聽了也會嚇一跳的吧？你猜是誰？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"너 또 그런다?","JPN":"また前置きが長いんだけど？","ENG":"This again?","TWN":"你又這樣？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"아, 아하하…… 마술사는 흥미를 이끌어내는 기술이 중요하거든.","JPN":"あ、あはは……マジシャンは観客の興味を引きつけるスキルが大事だからね。","ENG":"A-ah hah hah... a magician needs to know how to elicit interest from a crowd.","TWN":"哈哈哈……魔術師的重要技巧就是引人入勝。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"PENCIL_SCHOOL_NPC_NULL","text":{"KOREA":"어쨌든 그 선생님은 바로……!","JPN":"とにかく、その先生があの……！","ENG":"Anyway, our new teacher is...!","TWN":"總之，那位老師就是……！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"PENCIL_SCHOOL_NPC_NULL","face":"UNIT_LAUGH"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"},{"id":"L43_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"야들아, 수업 시작한 지가 언젠데 아직도 떠들고 있나? 어서 자리들 앉아라.","JPN":"みんな、もう授業始まっとるで。早く席に座りなさい。","ENG":"Hey, what are y'all doin' still chattin'? Class has already started, so get back in your seats.","TWN":"你們幾個，上課都開始多久了還在吵？快點回到座位上。"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L44_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"아오 또 누구얏! 흐름 끊는 게!!","JPN":"ああまた誰よ！　なんで割り込んでくるの！！","ENG":"Oh, come on! Who's cutting us off this time?!","TWN":"又是誰啊！打斷我說話！！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L46_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"아하하, 내가 또 방해했나?","JPN":"あはは、またウチが邪魔してもうたんかな？","ENG":"Ah hah hah! Am I botherin' you again?","TWN":"哈哈哈，我又打擾到你了嗎？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L47_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"잠깐, 그 목소린……?!","JPN":"待って、この声……！？","ENG":"Hold on... That voice...!","TWN":"等等，這個聲音是……？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L48_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"내는 오늘부터 니들 수업을 담당할 미리네라고 한다. 잘 부탁할게~","JPN":"今日からこの授業を担当するオノデラ・マリや。よろしくな！","ENG":"I'm Mi Rinae, your teacher for this class starting today. Nice to meet y'all.","TWN":"從今天起由我來負責你們的課程，我叫宓璃奈，請多多指教囉～"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L49_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"자 그럼…… 오리앤테이션을 해야겠제?","JPN":"ほな……オリエンテーションから始めなあかんけど。","ENG":"Okay, then... we should do an orientation class, right?","TWN":"那麼……我們該進行新學期說明會了吧？"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L50_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"……아이! 내는 그런 딱딱한 건 질색이다!","JPN":"……ウチはそういう堅苦しいのは好かん！","ENG":"...Eh! I'm not a big fan of formalities like that!","TWN":"……哎呀! 我最討厭這種死板的東西了！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L1_1","type":"dialog","speaker":"STAR_PROMISE_NULL_NULL","text":{"KOREA":"다들 운동장으로 집합! 너희 나이 때는 원래 공차면서 노는 게 최고다!","JPN":"みんな運動場に集合！　あんたたちの年頃は、サッカーでもして遊ぶのがいちばんや！","ENG":"Everyone, gather 'round the track! What you all oughta be doin' at your age is kickin' balls and havin' a good time!","TWN":"大家操場集合！你們這個年紀就應該多多運動！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L2_1","type":"dialog","speaker":"TWINTAIL_ACADEMY_NULL_NULL","text":{"KOREA":"또…… 또 당신이야?!","JPN":"また……またあんたなの！？","ENG":"Y-you again?!","TWN":"又……又是你？！"},"stage":{"bg":"CLASS","bgm":"CUTSCENE_TALK_05","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"TWINTAIL_ACADEMY_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}},"sfx":"FX_CUTSCEN_TADA2"}]`);export{e as default};